const seedCustomers = async () => {
    try {
        await mongoose.connect(process.env.MONGO_URI || "mongodb://localhost:27017/bluecollar");
        console.log("MongoDB connected for seeding customers...");

        let created = 0;
        let skipped = 0;

        for (const c of customers) {
            const email = c.email.toLowerCase();
            const existing = await User.findOne({ email });
            if (existing) {
                console.log(`⏭ SKIP: ${c.name} (${email}) — already exists`);
                skipped++;
                continue;
            }

            const hashedPassword = await bcrypt.hash(c.password, 10);

            const user = new User({
                name: c.name,
                email,
                password: hashedPassword,
                role: "customer"
            });
            await user.save();

            const profile = new CustomerProfile({
                userId: user._id,
                mobile: c.mobileNumber,
                dateOfBirth: c.dateOfBirth ? new Date(c.dateOfBirth) : null,
                gender: c.gender,
                address: c.address,
                city: c.city,
                district: c.district,
                state: c.state,
                pincode: c.pincode,
                location: c.city,
                isVerified: true
            });
            await profile.save();

            console.log(`✅ ADDED: ${c.name} — ${email}`);
            created++;
        }

        console.log(`\n========================================`);
        console.log(`  Total Customers Added: ${created}`);
        console.log(`  Already Existed:       ${skipped}`);
        console.log(`  Total in Script:       ${customers.length}`);
        console.log(`========================================\n`);

        process.exit(0);
    } catch (err) {
        console.error("Error seeding customers:", err.message);
        process.exit(1);
    }
};

seedCustomers();
